@rendermode InteractiveServer

<div class="@DropZoneClass"
     @ondragenter="HandleDragEnter"
     @ondragenter:preventDefault
     @ondragleave="HandleDragLeave"
     @ondragover:preventDefault
     @ondrop="HandleDrop"
     @ondrop:preventDefault>
    <InputFile OnChange="OnFilesSelected" multiple class="file-drop-input" />
    <p class="file-drop-text">Drag &amp; drop files here, or click to browse</p>
</div>

@if (_entries.Count > 0)
{
    <ul class="file-drop-list">
        @foreach (var entry in _entries)
        {
            <li class="file-drop-item @(entry.IsOversize ? "file-drop-error" : "")">
                <div class="file-drop-details">
                    @if (entry.IsOversize)
                    {
                        <span class="file-drop-error-msg">
                            <strong>@entry.Info.Name</strong> — @FormatSize(entry.Info.Size) — exceeds the 10 MB limit
                        </span>
                    }
                    else
                    {
                        <span><strong>@entry.Info.Name</strong></span>
                        <span>@FormatSize(entry.Info.Size)</span>
                        <span>@entry.Info.Type</span>
                    }
                </div>
                <button class="btn btn-sm btn-outline-danger" @onclick="() => Remove(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSize = 10L * 1024 * 1024;

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private readonly List<FileEntry> _entries = new();
    private int _dragCounter;

    private string DropZoneClass =>
        _dragCounter > 0 ? "file-drop-zone file-drop-zone-active" : "file-drop-zone";

    private void HandleDragEnter() => _dragCounter++;
    private void HandleDragLeave() => _dragCounter--;

    private async Task HandleDrop()
    {
        _dragCounter = 0;
        await Task.CompletedTask;
    }

    private async Task OnFilesSelected(InputFileChangeEventArgs e)
    {
        _dragCounter = 0;

        foreach (var file in e.GetMultipleFiles(100))
        {
            var info = new FileInfo(file.Name, file.Size, file.ContentType);
            _entries.Add(new FileEntry(info, file.Size > MaxFileSize));
        }

        await NotifyParent();
    }

    private async Task Remove(FileEntry entry)
    {
        _entries.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _entries
            .Where(e => !e.IsOversize)
            .Select(e => e.Info)
            .ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    private sealed record FileEntry(FileInfo Info, bool IsOversize);
}

.file-drop-zone {
    position: relative;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 180px;
    border: 2px dashed #90a4ae;
    border-radius: 8px;
    background-color: #f5f7fa;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: pointer;
}

.file-drop-zone-active {
    border-color: #1976d2;
    background-color: #e3f2fd;
}

.file-drop-input {
    position: absolute;
    inset: 0;
    opacity: 0;
    cursor: pointer;
}

.file-drop-text {
    color: #607d8b;
    pointer-events: none;
    margin: 0;
}

.file-drop-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-drop-item {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-drop-item.file-drop-error {
    border-color: #dc3545;
    background-color: #fff5f5;
}

.file-drop-details {
    display: flex;
    gap: 1rem;
    flex-wrap: wrap;
    align-items: center;
}

.file-drop-error-msg {
    color: #dc3545;
}

