.file-drop-zone {
    position: relative;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 180px;
    border: 2px dashed #90a4ae;
    border-radius: 8px;
    background-color: #f5f7fa;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: pointer;
}

.file-drop-zone-active {
    border-color: #1976d2;
    background-color: #e3f2fd;
}

.file-drop-input {
    position: absolute;
    inset: 0;
    opacity: 0;
    cursor: pointer;
}

.file-drop-text {
    color: #607d8b;
    pointer-events: none;
    margin: 0;
}

.file-drop-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-drop-item {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-drop-item.file-drop-error {
    border-color: #dc3545;
    background-color: #fff5f5;
}

.file-drop-details {
    display: flex;
    gap: 1rem;
    flex-wrap: wrap;
    align-items: center;
}

.file-drop-error-msg {
    color: #dc3545;
}

